std::mutex mtx;
std::condition_variable cv_not_full;
std::condition_variable cv_not_empty;
std::queue<int> buffer;

void producer(int id, int items) {
    for (int i = 0; i < items; ++i) {
        std::unique_lock<std::mutex> lock(mtx);

        // Wait if buffer is full
        cv_not_full.wait(lock, []{ return buffer.size() < MAX_BUFFER_SIZE; });

        buffer.push(i);
        std::cout << "Producer " << id << " produced " << i
                  << " (buffer size: " << buffer.size() << ")\n";

        cv_not_empty.notify_one();  // Wake consumer
    }
}

void consumer(int id, int items) {
    for (int i = 0; i < items; ++i) {
        std::unique_lock<std::mutex> lock(mtx);

        // Wait if buffer is empty
        cv_not_empty.wait(lock, []{ return !buffer.empty(); });

        int value = buffer.front();
        buffer.pop();
        std::cout << "Consumer " << id << " consumed " << value
                  << " (buffer size: " << buffer.size() << ")\n";

        cv_not_full.notify_one();  // Wake producer
    }
}

int main() {
    std::thread p1(producer, 1, 10);
    std::thread c1(consumer, 1, 10);

    p1.join();
    c1.join();
}

#include <queue>
#include <mutex>
#include <condition_variable>
#include <optional>

template<typename T>
class ThreadSafeQueue {
private:
    mutable std::mutex mtx;
    std::condition_variable cv;
    std::queue<T> queue;

public:
    void push(T value) {
        {
            std::lock_guard<std::mutex> lock(mtx);
            queue.push(std::move(value));
        }
        cv.notify_one();
    }

    T pop() {
        std::unique_lock<std::mutex> lock(mtx);
        cv.wait(lock, [this]{ return !queue.empty(); });

        T value = std::move(queue.front());
        queue.pop();
        return value;
    }

    std::optional<T> try_pop(std::chrono::milliseconds timeout) {
        std::unique_lock<std::mutex> lock(mtx);

        if (!cv.wait_for(lock, timeout, [this]{ return !queue.empty(); })) {
            return std::nullopt;  // Timeout
        }

        T value = std::move(queue.front());
        queue.pop();
        return value;
    }

    bool empty() const {
        std::lock_guard<std::mutex> lock(mtx);
        return queue.empty();
    }
};

// Usage
int main() {
    ThreadSafeQueue<int> queue;

    std::thread producer([&]{
        for (int i = 0; i < 5; ++i) {
            queue.push(i);
            std::cout << "Pushed " << i << "\n";
        }
    });

    std::thread consumer([&]{
        for (int i = 0; i < 5; ++i) {
            int value = queue.pop();
            std::cout << "Popped " << value << "\n";
        }
    });

    producer.join();
    consumer.join();
}

