          prom.set_value(result);
      } catch (...) {
          prom.set_exception(std::current_exception());
      }
  });

  try {
      int val = fut.get();  // May rethrow exception
  } catch (const std::exception& e) {
      std::cerr << "Caught from thread: " << e.what() << "\n";
  }

  t.join();

